import "@radix-ui/themes/styles.css";
import { Box, ThemePanel, Container, Flex, Section, Heading, Link } from "@radix-ui/themes";
import './App.css';
// import { useState, Component } from "react";
import React from "react";

class Navigation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            pagePosition: 0,
            aboutHeight: 0,
            experienceHeight: 0,
            projectsHeight: 0,
            currentSection: "about"
        }
        this.handleScroll = this.handleScroll.bind(this);
    }

    handleScroll() {
        console.log("scrolling");
    }

    componentDidMount() {
        const about = document.getElementById("about");
        const experience = document.getElementById("experience");
        const projects = document.getElementById("projects");
        this.setState({
            aboutHeight: about.offsetTop,
            // experienceHeight: experience.offsetTop,
            // projectsHeight: projects.offsetTop,
        })
        window.addEventListener('scroll', this.handleScroll);
    }

    render() {
        const currentSection = this.state.currentSection;
        return (
            <Box>
                <Flex gap="4" direction="column" mb="7">
                    <Link height="100%" className="nav-container">
                        <span className={currentSection == "about" ? "nav-selected" : "nav-select"}></span>
                        <Link className="navigation_button" style={currentSection != "about" ? { color: "#ffffff9e" } : { color: "white" }} href="#about" weight="bold">ABOUT</Link>
                    </Link>
                    {/* <Box>
                        <Link className="navigation_button" style={currentSection != "experience" ? { color: "#ffffff9e" } : { color: "white" }} href="#experience" weight="bold"><span className={currentSection == "experience" ? "nav-selected" : "nav-select"}></span>EXPERIENCE</Link>
                    </Box>
                    <Box>
                        <Link className="navigation_button" style={currentSection != "projects" ? { color: "#ffffff9e" } : { color: "white" }} href="#projects" weight="bold"><span className={currentSection == "projects" ? "nav-selected" : "nav-select"}></span>PROJECTS</Link>
                    </Box> */}
                </Flex>
            </Box>
        );
    }
}

export default Navigation;
